import json

def average_treatment_effectiveness(feedback, treatment_name):
    # Filter feedback where the treatment exists
    filtered_feedback = [patient for patient in feedback if treatment_name in patient["treatments"]]

    # Calculate the sum of effectiveness ratings for the specified treatment
    total_effectiveness = sum(patient["treatments"][treatment_name] for patient in filtered_feedback)

    # Calculate the number of patients who provided feedback for the treatment
    num_patients = len(filtered_feedback)

    # If no patients provided feedback, return 0.0
    if num_patients == 0:
        return 0.0

    # Calculate average effectiveness
    average = total_effectiveness / num_patients

    # Return the average rounded to two decimal places
    return round(average, 2)

